import java.util.*;
interface Scorer {
    int score(String s);
}

public class Main {
    public static List<String> top(List<String> words, Scorer scorer, int limit) {
        List<String> copy = new ArrayList<>(words);
        copy.sort((a, b) -> scorer.score(b) - scorer.score(a));
        return copy.subList(0, Math.min(limit, copy.size()));
    }

    public static void main(String[] args) {
        List<String> words = List.of("hi", "hello", "hey");
        Scorer byLength = s -> s.length();
        System.out.println(top(words, byLength, 2));
    }
}
